class Solution(object):
    def addOperators(self, num, target):
        """
        :type num: str
        :type target: int
        :rtype: List[str]
        """
        def dfs(index, path, value, last):
            if index == len(num):
                if value == target:
                    result.append(path)
                return
            for i in range(index + 1, len(num) + 1):
                num_str = num[index:i]
                num_int = int(num_str)
                if num_str != "0":
                    if index == 0:
                        dfs(i, num_str, num_int, num_int)
                    else:
                        dfs(i, path + "+" + num_str, value + num_int, num_int)
                        dfs(i, path + "-" + num_str, value - num_int, -num_int)
                        dfs(i, path + "*" + num_str, value - last + last * num_int, last * num_int)
                else:
                    if index == 0:
                        dfs(i, num_str, num_int, num_int)
                    else:
                        dfs(i, path + "+" + num_str, value + num_int, num_int)
                        dfs(i, path + "-" + num_str, value - num_int, -num_int)
        result = []
        dfs(0, "", 0, 0)
        return result

