couples-holding-hands.solution:
class Solution(object):
    def minSwapsCouples(self, row):
        """
        :type row: List[int]
        :rtype: int
        """
        n = len(row)
        uf = UnionFind(n)
        for i in range(0, n, 2):
            uf.union(row[i], row[i+1])
        return n // 2 - uf.count

class UnionFind(object):
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
        self.count = n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x == root_y:
            return
        if self.rank[root_x] < self.rank[root_y]:
            self.parent[root_x] = root_y
        else:
            self.parent[root_y] = root_x
            if self.rank[root_x] == self.rank[root_y]:
                self.rank[root_x] += 1
        self.count -= 1

shortest-palindrome.solution:
class Solution(object):
    def shortestPalindrome(self, s):
        """
        :type s: str
        :rtype: str
        """
        rev_s = s[::-1]
        l = self.get_longest_prefix_length(s + '#' + rev_s)
        return rev_s[:len(s) - l] + s

    def get_longest_prefix_length(self, s):
        n = len(s)
        prefix_length = [0] * n
        j = 0
        for i in range(1, n):
            while j > 0 and s[i] != s[j]:
                j = prefix_length[j - 1]
            if s[i] == s[j]:
                j += 1
            prefix_length[i] = j
        return prefix_length[-1]

self-crossing.solution:
def isSelfCrossing(distance):
    for i in range(3, len(distance)):
        # Check if the current path crosses with the previous one
        if distance[i] >= distance[i - 2] and distance[i - 1] <= distance[i - 3]:
            return True
        # Check for special case when the path is almost a straight line
        if i >= 4:
            if distance[i - 1] == distance[i - 3] and distance[i] + distance[i - 4] >= distance[i - 2]:
                return True
        # Check for special case when the path is almost a straight line
        if i >= 5:
            if distance[i] >= distance[i - 2] - distance[i - 4] >= 0 and distance[i - 3] - distance[i - 5] <= distance[i - 1] <= distance[i - 3]:
                return True
    return False

