class Solution(object):
    def longestPalindrome(self, s):
        """
        :type s: str
        :rtype: int
        """
        char_count = {}
        for char in s:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1

        length = 0
        odd_found = False
        for count in char_count.values():
            if count % 2 == 0:
                length += count
            else:
                length += count - 1
                odd_found = True

        if odd_found:
            length += 1

        return length

count-of-range-sum.solution:
def countRangeSum(nums, lower, upper):
    prefixSum = [0]*(len(nums)+1)
    for i in range(len(nums)):
        prefixSum[i+1] = prefixSum[i] + nums[i]
    def mergeSort(start, end):
        if start >= end: return 0
        mid = (start+end)//2
        count = mergeSort(start, mid) + mergeSort(mid+1, end)
        j, k = mid+1, mid+1
        for i in range(start, mid+1):
            while j <= end and prefixSum[j] - prefixSum[i] < lower: j += 1
            while k <= end and prefixSum[k] - prefixSum[i] <= upper: k += 1
            count += k-j
        prefixSum[start:end+1] = sorted(prefixSum[start:end+1])
        return count
    return mergeSort(0, len(nums))

