remove-invalid-parentheses.solution:
from collections import deque

def isValid(s):
    count = 0
    for char in s:
        if char == '(':
            count += 1
        elif char == ')':
            count -= 1
        if count < 0:
            return False
    return count == 0

def removeInvalidParentheses(s):
    bfs = deque()
    memo = set()
    ans = []
    bfs.append(s)
    while bfs:
        cur_s = bfs.popleft()
        if isValid(cur_s):
            ans.append(cur_s)
        if not ans:
            for i in range(len(cur_s)):
                if cur_s[i] in ('(', ')'):
                    next_s = cur_s[:i]+cur_s[i+1:]
                    if next_s not in memo:
                        memo.add(next_s)
                        bfs.append(next_s)
    return ans

