from collections import deque

class Solution(object):
    def containVirus(self, isInfected):
        """
        :type isInfected: List[List[int]]
        :rtype: int
        """
        m, n = len(isInfected), len(isInfected[0])
        dirs = [(1,0),(0,1),(-1,0),(0,-1)]

        def spread(i, j):
            q = deque([(i, j)])
            infected.add((i, j))
            threaten = set()
            while q:
                x, y = q.popleft()
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n:
                        if isInfected[nx][ny] == 1 and (nx, ny) not in infected:
                            q.append((nx, ny))
                            infected.add((nx, ny))
                        elif isInfected[nx][ny] == 0:
                            threaten.add((nx, ny))
            return threaten

        res = 0
        for _ in range(m * n):
            infected = set()
            threatens = []
            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == 1 and (i, j) not in infected:
                        threatens.append(spread(i, j))
            if not threatens:
                break
            threatens.sort(key=len, reverse=True)
            res += len(threatens[-1])
            for i, j in threatens[-1]:
                isInfected[i][j] = -1
            for threaten in threatens[:-1]:
                for i, j in threaten:
                    isInfected[i][j] = 1
        return res

