class Solution(object):
    def longestIncreasingPath(self, matrix):
        if not matrix or not matrix[0]:
            return 0

        memo = {}  # dictionary to store the longest path length from each cell
        max_path = 0  # variable to store the maximum path length

        # iterate over all cells in the matrix
        for i in range(len(matrix)):
            for j in range(len(matrix[0])):
                max_path = max(max_path, self.dfs(matrix, i, j, memo))

        return max_path

    def dfs(self, matrix, i, j, memo):
        # base case: if the current cell is already visited
        if (i, j) in memo:
            return memo[(i, j)]

        # initialize the longest path length as 1
        max_path = 1
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]  # left, right, up, down

        # iterate over all possible directions
        for dx, dy in directions:
            x, y = i + dx, j + dy

            # check if the new cell is within the matrix and the value is greater
            if 0 <= x < len(matrix) and 0 <= y < len(matrix[0]) and matrix[x][y] > matrix[i][j]:
                max_path = max(max_path, 1 + self.dfs(matrix, x, y, memo))

        # store the longest path length in the memo dictionary
        memo[(i, j)] = max_path

        return max_path

