class Solution(object):
    def wordBreak(self, s, wordDict):
        """
        :type s: str
        :type wordDict: List[str]
        :rtype: List[str]
        """
        wordSet = set(wordDict)
        memo = {}

        def dfs(s):
            if s in memo:
                return memo[s]
            if not s:
                return []

            res = []
            for i in range(1, len(s) + 1):
                if s[:i] in wordSet:
                    if i == len(s):
                        res.append(s[:i])
                    else:
                        sub_res = dfs(s[i:])
                        for item in sub_res:
                            res.append(s[:i] + ' ' + item)
            memo[s] = res
            return res

        return dfs(s)

