import heapq

def trapRainWater(heightMap):
    if not heightMap or not heightMap[0]:
        return 0

    m, n = len(heightMap), len(heightMap[0])
    pq = []
    seen = [[0] * n for _ in range(m)]

    # Add all boundary cells to the priority queue
    for i in range(m):
        for j in range(n):
            if i == 0 or j == 0 or i == m - 1 or j == n - 1:
                heapq.heappush(pq, (heightMap[i][j], i, j))
                seen[i][j] = 1

    result = 0
    while pq:
        height, i, j = heapq.heappop(pq)
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            x, y = i + dx, j + dy
            if 0 <= x < m and 0 <= y < n and not seen[x][y]:
                # If the current height is greater than the neighbor's height,
                # the neighbor is not trapped by the current cell
                if height > heightMap[x][y]:
                    result += height - heightMap[x][y]
                heapq.heappush(pq, (max(height, heightMap[x][y]), x, y))
                seen[x][y] = 1

    return result

