class Solution(object):
    def solve(self, board):
        if not board:
            return
        m, n = len(board), len(board[0])
        # mark the 'O's on the border and those connected to it
        for i in range(m):
            for j in range(n):
                if (i == 0 or j == 0 or i == m-1 or j == n-1) and board[i][j] == 'O':
                    self.dfs(board, i, j)
        # flip the 'O's that have not been marked
        for i in range(m):
            for j in range(n):
                if board[i][j] == 'O':
                    board[i][j] = 'X'
                elif board[i][j] == '#':
                    board[i][j] = 'O'

    def dfs(self, board, i, j):
        if i<0 or j<0 or i>=len(board) or j>=len(board[0]) or board[i][j] != 'O':
            return
        board[i][j] = '#'
        self.dfs(board, i-1, j)
        self.dfs(board, i+1, j)
        self.dfs(board, i, j-1)
        self.dfs(board, i, j+1)

