        :type cards: List[int]
        :rtype: bool
        """
        def helper(nums):
            if len(nums) == 1: return abs(nums[0] - 24) < 1e-6
            for i in range(len(nums)):
                for j in range(len(nums)):
                    if i != j:
                        new_nums = [nums[k] for k in range(len(nums)) if i != k != j]
                        if helper(new_nums + [nums[i] + nums[j]]): return True
                        if helper(new_nums + [nums[i] - nums[j]]): return True
                        if helper(new_nums + [nums[i] * nums[j]]): return True
                        if nums[j] != 0 and helper(new_nums + [nums[i] / nums[j]]): return True
            return False

        return helper(cards)

