class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)
        dp = [[[-1 for _ in range(n)] for _ in range(n)] for _ in range(2*n-1)]

        dp[0][0][0] = grid[0][0]

        for k in range(1, 2*n-1):
            for x1 in range(max(0, k-(n-1)), min(n-1, k)+1):
                y1 = k - x1
                if grid[x1][y1] == -1:
                    continue
                for x2 in range(x1, min(n-1, k)+1):
                    y2 = k - x2
                    if grid[x2][y2] == -1:
                        continue
                    max_cherries = -1
                    if x1 > 0 and y2 > 0:
                        max_cherries = max(max_cherries, dp[k-1][x1-1][x2-1])
                    if x1 > 0:
                        max_cherries = max(max_cherries, dp[k-1][x1-1][x2])
                    if x2 > 0:
                        max_cherries = max(max_cherries, dp[k-1][x1][x2-1])
                    max_cherries += grid[x1][y1]
                    if x1 != x2:
                        max_cherries += grid[x2][y2]
                    dp[k][x1][x2] = max_cherries

        return max(0, dp[2*n-2][n-1][n-1])

