from collections import Counter

class Solution(object):
    def findSubstring(self, s, words):
        """
        :type s: str
        :type words: List[str]
        :rtype: List[int]
        """
        if not s or not words:
            return []

        word_count = Counter(words)
        word_length = len(words[0])
        total_length = word_length * len(words)

        indices = []
        for i in range(len(s) - total_length + 1):
            window = s[i:i+total_length]
            if self.is_concatenated(window, word_count, word_length):
                indices.append(i)

        return indices

    def is_concatenated(self, window, word_count, word_length):
        window_count = Counter()
        for i in range(0, len(window), word_length):
            word = window[i:i+word_length]
            if word in word_count:
                window_count[word] += 1
                if window_count[word] > word_count[word]:
                    return False
            else:
                return False
        return True

