class Solution(object):
    def get_next(self, string):
        i, j = 0, -1
        next_val = [-1] * len(string)
        while i < len(string) - 1:
            if j == -1 or string[i] == string[j]:
                i += 1
                j += 1
                next_val[i] = j
            else:
                j = next_val[j]
        return next_val

    def repeatedSubstringPattern(self, s):
        next_val = self.get_next(s)
        if next_val[-1] != -1 and len(s) % (len(s) - (next_val[-1] + 1)) == 0:
            return True
        return False

