class Solution(object):
    def strongPasswordChecker(self, password):
        """
        :type password: str
        :rtype: int
        """

        # Check if password is already strong
        if len(password) < 6 or len(password) > 20:
            return max(6 - len(password), 0)

        # Initialize variables
        missing_types = 3
        repeat_count = 0
        replace_count = 0

        # Check for missing types of characters
        if any(c.islower() for c in password):
            missing_types -= 1
        if any(c.isupper() for c in password):
            missing_types -= 1
        if any(c.isdigit() for c in password):
            missing_types -= 1

        # Check for repeating characters
        i = 2
        while i < len(password):
            if password[i] == password[i-1] == password[i-2]:
                repeat_count += 1
                i += 3
            else:
                i += 1

        # Calculate number of replacements needed
        replace_count = max(repeat_count - (len(password) - 20), 0)

        # Calculate total number of steps needed
        total_steps = max(len(password) - 20, 0) + replace_count + missing_types

        return total_steps

