            return 0

        m, n = len(matrix), len(matrix[0])
        height = [0] * (n + 1)
        max_area = 0

        for i in range(m):
            for j in range(n):
                height[j] = height[j] + 1 if matrix[i][j] == '1' else 0

            stack = [-1]
            for j in range(n + 1):
                while height[j] < height[stack[-1]]:
