class Solution(object):
    def findWords(self, board, words):
        """
        :type board: List[List[str]]
        :type words: List[str]
        :rtype: List[str]
        """
        # Build the trie
        trie = {}
        for word in words:
            node = trie
            for letter in word:
                node = node.setdefault(letter, {})
            node['#'] = word
        self.res = []
        for i in range(len(board)):
            for j in range(len(board[0])):
                if board[i][j] in trie:
                    self.dfs(board, i, j, trie)
        return self.res

    def dfs(self, board, i, j, trie):
        letter = board[i][j]
        currentNode = trie[letter]
        matchWord = currentNode.pop('#', False)
        if matchWord:
            self.res.append(matchWord)
        board[i][j] = '$'
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            x, y = i + dx, j + dy
            if 0 <= x < len(board) and 0 <= y < len(board[0]) and board[x][y] in currentNode:
                self.dfs(board, x, y, currentNode)
        board[i][j] = letter
        if not currentNode:
            trie.pop(letter)

