class Solution(object):
    def findAllConcatenatedWordsInADict(self, words):
        """
        :type words: List[str]
        :rtype: List[str]
        """
        res = []
        preWords = set()
        words.sort(key=len)
        for word in words:
            if self.dfs(word, preWords, 0):
                res.append(word)
            preWords.add(word)
        return res

    def dfs(self, word, preWords, start):
        if start == len(word):
            return True
        for end in range(start + 1, len(word) + 1):
            if word[start:end] in preWords and self.dfs(word, preWords, end):
                return True
        return False

base-7.solution:
class Solution(object):
    def convertToBase7(self, num):
        """
        :type num: int
        :rtype: str
        """
        if num < 0:
            return '-' + self.convertToBase7(-num)
        result = ''
        while num:
            result = str(num % 7) + result
            num //= 7
        return result or '0'

